#include <omp.h>

#define N 2048

#define IDX(i, j) ((i) + (j) * N)

void initialize_data(float* f) {
  for (int j = 0; j < N; ++j) {
    for (int i = 0; i < N; ++i) {

      if (i == 0 || i == N-1) {
        f[IDX(i,j)] = sinf(j * 2 * M_PI / (N - 1));
      }
      else if (j == 0 || j == N-1) {
        f[IDX(i,j)] = sinf(i * 2 * M_PI / (N - 1));
      }
      else {
        f[IDX(i,j)] = 0.0f;
      }

    }
  }
}

void jacobi_step(float* f, const float* f_old, float* error) {
  int i = omp_get_thread_num(); 
  int j = omp_get_thread_num(); 

  // Note: OpenMP Target does not map directly to CUDA's 2D grid/block/thread model with shared memory shuffling.
  // We restructure the logic to use standard OpenMP parallelism over the 2D grid.
  // The shared memory tile optimization and shuffle reductions from the CUDA version are algorithm-specific optimizations
  // that rely on the specific hardware thread block structure. To preserve the *algorithm* (Jacobi iteration) and 
  // *I/O behavior* (convergence to same result within tolerance) while targeting OpenMP, we implement the standard 
  // parallel Jacobi step with a global reduction for error.

  // This function is designed to be called from an omp target region.
  // The loop bounds and reduction are handled by the caller's pragma directives.
}

int main() {
  auto start_time = std::chrono::steady_clock::now();

  float* f = (float*)aligned_alloc(64, N * N * sizeof(float));
  float* f_old = (float*)aligned_alloc(64, N * N * sizeof(float));

  initialize_data(f);
  initialize_data(f_old);

  float error = std::numeric_limits<float>::max();
  const float tolerance = 1.e-5f;

  const int max_iters = 10000;
  int num_iters = 0;

  auto start = std::chrono::steady_clock::now();

  #pragma omp target device(gpu)
  {
    float* d_f = (float*)omp_target_alloc(N * N * sizeof(float), omp_get_device_num());
    float* d_f_old = (float*)omp_target_alloc(N * N * sizeof(float), omp_get_device_num());
    float* d_error = (float*)omp_target_alloc(sizeof(float), omp_get_device_num());

    // Copy initial data
    omp_target_memcpy(d_f, f, N * N * sizeof(float), 0, 0, omp_get_device_num(), omp_get_initial_device());
    omp_target_memcpy(d_f_old, f_old, N * N * sizeof(float), 0, 0, omp_get_device_num(), omp_get_initial_device());

    while (error > tolerance && num_iters < max_iters) {
      float local_error = 0.0f;

      #pragma omp target teams distribute parallel for collapse(2) reduction(+:local_error)
      for (int j = 0; j < N; ++j) {
        for (int i = 0; i < N; ++i) {
          float val = 0.0f;
          float err_val = 0.0f;

          if (j >= 1 && j <= N-2 && i >= 1 && i <= N-2) {
            val = 0.25f * (d_f_old[IDX(i+1, j)] + 
                           d_f_old[IDX(i-1, j)] + 
                           d_f_old[IDX(i, j+1)] + 
                           d_f_old[IDX(i, j-1)];

            float df = val - d_f_old[IDX(i, j)];
            err_val = df * df;

            d_f[IDX(i, j)] = val;
          } else if (i == 0 || i == N-1 || j == 0 || j == N-1) {
            // Boundary conditions (though typically unchanged in Jacobi if initialized correctly)
            // Re-apply boundary to ensure consistency if swapped
            if (i == 0 || i == N-1) {
              val = sinf(j * 2 * M_PI / (N - 1));
            } else {
              val = sinf(i * 2 * M_PI / (N - 1));
            }
            d_f[IDX(i, j)] = val;
          }

          local_error += err_val;
        }
      }

      // Update global error
      #pragma omp target update(local_error)
      error = local_error;

      // Swap pointers on device
      std::swap(d_f, d_f_old);

      // Read error back to host
      omp_target_memcpy(&error, d_error, sizeof(float), 0, 0, omp_get_initial_device(), omp_get_device_num());

      // The reduction above calculated sum of squares. 
      // We need to normalize and sqrt.
      // Note: The reduction variable 'local_error' in the loop above accumulates the sum.
      // We must copy that accumulated sum to the host or a device scalar to process.
      // Let's refine the reduction logic to match the CUDA atomicAdd pattern more closely in spirit, 
      // but using OpenMP reduction is cleaner.

      // Correction: The reduction variable 'local_error' is local to the target region execution.
      // We need to copy it out.
      float total_sq_error = 0.0f;
      // Actually, the reduction clause handles the accumulation. 
      // We just need to make sure 'error' gets the value.
      // Since 'error' is host variable, we use a device variable for the reduction then copy.

      // Re-doing the loop structure for clarity and correctness with OpenMP Target:
      float d_error_val = 0.0f;

      #pragma omp target teams distribute parallel for collapse(2) reduction(+:d_error_val)
      for (int j = 1; j < N-1; ++j) {
        for (int i = 1; i < N-1; ++i) {
          float new_val = 0.25f * (d_f_old[IDX(i+1, j)] + 
                                   d_f_old[IDX(i-1, j)] + 
                                   d_f_old[IDX(i, j+1)] + 
                                   d_f_old[IDX(i, j-1]);

          float df = new_val - d_f_old[IDX(i, j)];
          d_error_val += df * df;

          d_f[IDX(i, j)] = new_val;
        }
      }

      // Copy the reduced error value to host
      omp_target_memcpy(&error, &d_error_val, sizeof(float), 0, 0, omp_get_initial_device(), omp_get_device_num());

      // Normalize and sqrt
      error = sqrtf(error / ((N-2) * (N-2))); // Approx N*N as in original, strictly it's interior points

      if (num_iters % 1000 == 0) {
        std::cout << "Error after iteration " << num_iters << " = " << error << std::endl;
      }

      ++num_iters;

      // Swap host pointers for next iteration logic (though device pointers swapped inside)
      // Actually, we swapped d_f and d_f_old inside the target. 
      // We need to ensure the next iteration uses the updated d_f_old.
      // The swap(std::swap(d_f, d_f_old)) inside the loop handles the device pointers.
    }

    omp_target_free(d_f, omp_get_device_num());
    omp_target_free(d_f_old, omp_get_device_num());
    omp_target_free(d_error, omp_get_device_num());
  }

  auto end = std::chrono::steady_clock::now();
  auto time = std::chrono::duration_cast<std::chrono::nanoseconds>(end - start).count();
  std::cout << "Average execution time per iteration: " << (time * 1e-9f) / num_iters << " (s)\n";

  if (error <= tolerance && num_iters < max_iters) {
    std::cout << "PASS" << std::endl;
  }
  else {
    std::cout << "FAIL" << std::endl;
    free(f);
    free(f_old);
    return -1;
  }

  free(f);
  free(f_old);

  auto end_time = std::chrono::steady_clock::now();
  auto total_time = std::chrono::duration_cast<std::chrono::nanoseconds>(end_time - start_time).count();
  double duration = total_time * 1e-9;
  std::cout << "Total elapsed time: " << std::setprecision(4) << duration << " seconds" << std::endl;

  return 0;
}
